import { memo } from "react";
import { ShoppingBag, CalendarCheck, PenLine, ThumbsUp, ThumbsDown } from "lucide-react";
import { Link } from "react-router-dom";
import mapIcon from "@/assets/map-icon.png";
import { useStoryReactions } from "@/hooks/useStoryReactions";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";

const useAboutUsReactions = () => {
  const { data: contentId } = useQuery({
    queryKey: ["about-us-content-id"],
    queryFn: async () => {
      const { data } = await supabase
        .from("about_us_content")
        .select("id")
        .limit(1)
        .single();
      return data?.id || null;
    },
    staleTime: 1000 * 60 * 10,
  });
  const { counts } = useStoryReactions(contentId || undefined, "about_us");
  return counts;
};

const StatsDisplay = memo(({ stats, t }: { stats: { order_count: number; reserve_count: number }; t: (key: string) => string }) => {
  const counts = useAboutUsReactions();
  
  return (
    <div className="absolute top-16 sm:top-20 left-3 right-3 z-20">
      <div className="gap-4 w-full flex-col flex items-start justify-start">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <ShoppingBag className="w-4 h-4 text-primary" />
            <span className="text-sm text-white/90 drop-shadow-md">{t("home.stats.delivery")}</span>
            <span className="font-bold text-white text-sm drop-shadow-md">{stats.order_count}</span>
          </div>
          <div className="flex items-center gap-2">
            <CalendarCheck className="w-4 h-4 text-accent" />
            <span className="text-sm text-white/90 drop-shadow-md">{t("home.stats.reservation")}</span>
            <span className="font-bold text-white text-sm drop-shadow-md">{stats.reserve_count}</span>
          </div>
        </div>
        
        <div className="flex items-end justify-between w-full">
          <span className="text-xl sm:text-2xl font-bold text-white drop-shadow-md">
            {t("home.hero.brandName")}
            <img 
              src={mapIcon} 
              alt="map icon" 
              width={28}
              height={28}
              loading="eager"
              decoding="async"
              className="inline-block w-6 sm:w-7 h-6 sm:h-7 object-contain ml-1 align-middle" 
            />
          </span>
          <div className="flex items-center gap-2">
            <Link
              to="/about-us"
              className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-medium text-white bg-white/10 hover:bg-white/20 backdrop-blur-sm border border-white/20 shadow-soft transition-all duration-300 hover:scale-105 group"
            >
              <PenLine className="w-4 h-4 text-primary drop-shadow-[0_0_4px_hsl(174_100%_25%/0.6)] group-hover:rotate-[-12deg] transition-transform duration-300" />
              <span>{t("home.hero.confession")}</span>
            </Link>
            {(counts.likes > 0 || counts.dislikes > 0) && (
              <div className="flex items-center gap-2 text-xs text-white/80 drop-shadow-md">
                {counts.likes > 0 && (
                  <span className="inline-flex items-center gap-1">
                    <ThumbsUp className="w-3 h-3" /> {counts.likes}
                  </span>
                )}
                {counts.dislikes > 0 && (
                  <span className="inline-flex items-center gap-1">
                    <ThumbsDown className="w-3 h-3" /> {counts.dislikes}
                  </span>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
});
StatsDisplay.displayName = "StatsDisplay";

export default StatsDisplay;
